use strict;
use warnings;

if (@ARGV < 1) {
    die "Usage: $0 filename\n";
}

open my $fh, '<', $ARGV[0] or die "$0: Cannot open '$ARGV[0]' - $!\n";

while (my $line = <$fh>) {
    chomp $line;
    $line =~ /[\w\.-]+@[\w\.-]+/g;
    print while $_; # Print each match
}
